import Link from "next/link";

import { MetadataRow, SectionHeading, Surface, TagChip, TagList } from "@/components/ui/primitives";
import { listPublishedContent } from "@/features/public-content/service";

const publishedDateFormatter = new Intl.DateTimeFormat("en", { dateStyle: "medium" });

type PublishedContent = Awaited<ReturnType<typeof listPublishedContent>>[number];
type ContentPreviewVariant = "compact" | "balanced" | "feature";

function getDisplayUrl(url: string) {
  try {
    const parsedUrl = new URL(url);
    const pathname = parsedUrl.pathname === "/" ? "" : parsedUrl.pathname;

    return `${parsedUrl.host}${pathname}`;
  } catch {
    return url.replace(/^https?:\/\//, "");
  }
}

function getContentPreviewVariant(item: PublishedContent): ContentPreviewVariant {
  if (item.kind === "note") {
    const hasSummary = Boolean(item.summary?.trim());
    const excerptLength = item.excerpt.trim().length;

    if (hasSummary && (excerptLength > 112 || item.tags.length >= 2)) {
      return "feature";
    }

    if (!hasSummary && excerptLength < 96 && item.tags.length <= 1) {
      return "compact";
    }

    return "balanced";
  }

  const hasSummary = Boolean(item.summary?.trim());
  const displayUrl = getDisplayUrl(item.url);

  if (hasSummary && (displayUrl.length > 32 || item.tags.length >= 2)) {
    return "feature";
  }

  if (!hasSummary && displayUrl.length < 32 && item.tags.length <= 1) {
    return "compact";
  }

  return "balanced";
}

function PublishedContentPreviewCard({ item }: { item: PublishedContent }) {
  const variant = getContentPreviewVariant(item);
  const isNote = item.kind === "note";
  const primaryPreview = isNote ? item.summary?.trim() || item.excerpt.trim() || "Published note" : item.summary?.trim() || "Published link";
  const supportingPreview =
    isNote && variant === "feature" && item.summary?.trim() && item.excerpt.trim() !== item.summary.trim()
      ? item.excerpt.trim()
      : null;

  return (
    <article
      className={`note-preview-card note-preview-card-${variant} public-content-card public-content-card-${item.kind}`}
      data-card-kind={item.kind}
      data-card-variant={variant}
    >
      <div className="note-preview-card-body">
        <h2 className="note-preview-card-title">
          {isNote ? (
            <Link className="note-list-link" href={`/notes/${item.slug}`}>
              {item.title}
            </Link>
          ) : (
            <a className="note-list-link" href={item.url} rel="noopener noreferrer" target="_blank">
              {item.title}
            </a>
          )}
        </h2>
        <div className="note-preview-card-copy">
          <p className="note-preview-card-summary">{primaryPreview}</p>
          {isNote ? (
            supportingPreview ? <p className="note-preview-card-excerpt">{supportingPreview}</p> : null
          ) : (
            <p className="note-preview-card-excerpt public-link-card-url">{getDisplayUrl(item.url)}</p>
          )}
        </div>
      </div>
      <MetadataRow className="note-preview-card-meta">
        <span>{isNote ? "Published note" : "Published link"}</span>
        <span>{publishedDateFormatter.format(item.publishedAt)}</span>
      </MetadataRow>
      <TagList aria-label={isNote ? "Published note tags" : "Published link tags"} className="note-preview-card-tags">
        {item.tags.length === 0 ? (
          <TagChip muted>No generated tags</TagChip>
        ) : (
          item.tags.map((tag) => (
            <TagChip key={tag.id}>
              {tag.name}
            </TagChip>
          ))
        )}
      </TagList>
    </article>
  );
}

export default async function HomePage() {
  const items = await listPublishedContent();
  const publishedNotes = items.filter((item) => item.kind === "note").length;
  const publishedLinks = items.filter((item) => item.kind === "link").length;
  const hasPublishedLinks = publishedLinks > 0;
  const publishedCountLabel = hasPublishedLinks
    ? `${items.length} public item${items.length === 1 ? "" : "s"}`
    : `${publishedNotes} published note${publishedNotes === 1 ? "" : "s"}`;

  return (
    <div className="feature-layout public-home-layout">
      <div className="public-home-grid">
        <Surface className="note-collection-panel" tone="panel">
          <div className="public-home-shell-head public-hero public-intro-panel">
            <div className="public-home-shell-copy">
              <p className="eyebrow">Public showroom</p>
              <h1>{hasPublishedLinks ? "Notes and links the owner has chosen to share." : "Notes the owner has chosen to share."}</h1>
              <p className="field-note lede">
                {hasPublishedLinks
                  ? "Published notes and published links lead the public surface. Drafts, private links, tags, and AI workflow stay inside the private studio until the owner chooses to publish them."
                  : "Published notes lead the public surface. Drafts, saved links, tags, and AI workflow stay inside the private studio until the owner chooses to publish them."}
              </p>
            </div>
            <div className="public-home-count" aria-label={hasPublishedLinks ? "Public archive size" : "Published note archive size"}>
              <span>Archive</span>
              <strong>{publishedCountLabel}</strong>
            </div>
          </div>
          <SectionHeading meta="Newest first" title={hasPublishedLinks ? "Published notes and links" : "Published notes"} />
          {items.length === 0 ? (
            <p>No published notes or links yet. The public site stays empty until the owner explicitly publishes one.</p>
          ) : (
            <div className="note-list public-note-list public-note-showroom" data-testid="public-home-showroom">
              {items.map((item) => (
                <PublishedContentPreviewCard key={`${item.kind}-${item.id}`} item={item} />
              ))}
            </div>
          )}
        </Surface>
      </div>
    </div>
  );
}

import "dotenv/config";

import { expect, test } from "@playwright/test";

import { setAiPlaywrightTestMode } from "./ai-test-mode";

// These journeys all mutate the same single-owner SQLite state, so serial execution keeps promotion checks deterministic.
test.describe.configure({ mode: "serial" });

test("public homepage exposes the mixed published content surface", async ({ page }) => {
  await page.goto("/");

  const emptyState = page.getByText("No published notes or links yet.");
  const publishedNoteEntry = page.locator(".note-preview-card").first();

  await expect(
    page
      .getByRole("heading", { name: "Notes the owner has chosen to share." })
      .or(page.getByRole("heading", { name: "Notes and links the owner has chosen to share." }))
  ).toBeVisible();
  await expect(page.getByRole("navigation").getByRole("link", { name: "Owner login" })).toBeVisible();
  await expect(emptyState.or(publishedNoteEntry)).toBeVisible();
});

test("anonymous visitors cannot access the owner search route", async ({ page }) => {
  await page.goto("/app/search");

  await expect(page).toHaveURL(/\/login/);
});

test("owner can sign in, create a draft note, edit it, and reopen it with rendered preview", async ({ page }) => {
  const username = process.env.OWNER_USERNAME ?? "owner";
  const password = process.env.OWNER_PASSWORD ?? "password";
  const uniqueId = `${Date.now()}`;
  const initialTitle = `Draft note ${uniqueId}`;
  const updatedTitle = `Updated draft note ${uniqueId}`;
  const initialMarkdown = `# Preview ${uniqueId}

- first item
- second item`;
  const updatedMarkdown = `## Revised ${uniqueId}

Paragraph with **bold** text and a [link](https://example.com).`;

  await page.goto("/app/notes/new");
  await expect(page).toHaveURL(/\/login/);

  await page.getByLabel("Username").fill(username);
  await page.getByLabel("Password").fill(password);
  await page.getByRole("button", { name: "Sign in" }).click();

  await expect(page).toHaveURL(/\/app$/);
  await page.getByRole("link", { name: "New note" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/new$/);
  await page.getByRole("textbox", { name: /^Title$/ }).fill(initialTitle);
  await page.getByRole("textbox", { name: /^Markdown body$/ }).fill(initialMarkdown);

  const initialPreview = page.getByTestId("note-markdown-preview");
  await expect(initialPreview.getByRole("heading", { name: `Preview ${uniqueId}` })).toBeVisible();
  await expect(initialPreview.getByText("first item")).toBeVisible();

  await page.getByRole("button", { name: "Create draft" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?saved=1$/);
  await expect(page.getByText("Draft saved.")).toBeVisible();

  await page.getByRole("textbox", { name: /^Title$/ }).fill(updatedTitle);
  await page.getByRole("textbox", { name: /^Markdown body$/ }).fill(updatedMarkdown);

  const updatedPreview = page.getByTestId("note-markdown-preview");
  await expect(updatedPreview.getByRole("heading", { name: `Revised ${uniqueId}` })).toBeVisible();
  await expect(updatedPreview.getByText("bold")).toBeVisible();

  await page.getByRole("button", { name: "Save draft" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?saved=1$/);
  await expect(page.getByTestId("note-enrichment-panel")).toContainText("AI note metadata");
  await page.goto("/app");
  await expect(page.getByRole("link", { name: updatedTitle })).toBeVisible();

  await page.getByRole("link", { name: updatedTitle }).click();
  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit/);
  await expect(page.getByRole("textbox", { name: /^Title$/ })).toHaveValue(updatedTitle);
  await expect(page.getByRole("textbox", { name: /^Markdown body$/ })).toHaveValue(updatedMarkdown);
  await expect(page.getByTestId("note-markdown-preview").getByRole("heading", { name: `Revised ${uniqueId}` })).toBeVisible();
});

test("note save still succeeds when the configured AI endpoint times out and exposes a retry path", async ({ page }) => {
  const username = process.env.OWNER_USERNAME ?? "owner";
  const password = process.env.OWNER_PASSWORD ?? "password";
  const uniqueId = `${Date.now()}`;

  await setAiPlaywrightTestMode("timeout");

  try {
    await page.goto("/login");
    await page.getByLabel("Username").fill(username);
    await page.getByLabel("Password").fill(password);
    await page.getByRole("button", { name: "Sign in" }).click();

    await expect(page).toHaveURL(/\/app$/);
    await page.getByRole("link", { name: "New note" }).click();

    await page.getByRole("textbox", { name: /^Title$/ }).fill(`Retry note ${uniqueId}`);
    await page.getByRole("textbox", { name: /^Markdown body$/ }).fill(`Body for retry note ${uniqueId}`);
    await page.getByRole("button", { name: "Create draft" }).click();

    await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?saved=1$/);
    const enrichmentPanel = page.getByTestId("note-enrichment-panel");
    await expect(enrichmentPanel).toContainText("AI pending");
    await expect(enrichmentPanel).toContainText("AI failed", { timeout: 15000 });
    await expect(enrichmentPanel).toContainText("The Mina AI endpoint timed out.");
    await expect(page.getByTestId("note-ai-summary")).toHaveCount(0);
    await expect(page.getByRole("button", { name: "Retry AI enrichment" })).toBeVisible();

    await page.getByRole("button", { name: "Retry AI enrichment" }).click();

    await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?retried=1$/);
    await expect(page.getByText("Retry requested.")).toBeVisible();
    await expect(page.getByTestId("note-enrichment-panel")).toContainText("AI failed", { timeout: 15000 });
    await expect(page.getByTestId("note-enrichment-panel")).toContainText("The Mina AI endpoint timed out.");
  } finally {
    await setAiPlaywrightTestMode("passthrough");
  }
});

test("owner can publish and unpublish a note across the public routes", async ({ page }) => {
  const username = process.env.OWNER_USERNAME ?? "owner";
  const password = process.env.OWNER_PASSWORD ?? "password";
  const uniqueId = `${Date.now()}`;
  const title = `Public note ${uniqueId}`;
  const markdown = `## Shared heading ${uniqueId}

This note should appear on the public site when published.`;
  const slug = `public-note-${uniqueId}`;

  await page.goto("/login");
  await page.getByLabel("Username").fill(username);
  await page.getByLabel("Password").fill(password);
  await page.getByRole("button", { name: "Sign in" }).click();

  await expect(page).toHaveURL(/\/app$/);
  await page.getByRole("link", { name: "New note" }).click();
  await expect(page).toHaveURL(/\/app\/notes\/new$/);

  await page.getByRole("textbox", { name: /^Title$/ }).fill(title);
  await page.getByRole("textbox", { name: /^Markdown body$/ }).fill(markdown);
  await page.getByRole("button", { name: "Create draft" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?saved=1$/);
  await expect(page.getByText("Draft saved.")).toBeVisible();
  await expect(page.getByText("Private draft")).toBeVisible();

  await page.getByRole("button", { name: "Publish note" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?published=1$/);
  await expect(page.getByText("Note published.")).toBeVisible();
  await expect(page.getByRole("link", { name: "View public note" })).toBeVisible();

  await page.goto("/");
  const publicNoteEntry = page.locator(".note-preview-card").filter({ has: page.getByRole("link", { name: title }) });
  await expect(publicNoteEntry.getByRole("link", { name: title })).toBeVisible();
  await expect(publicNoteEntry.getByLabel("Published note tags")).toBeVisible();

  await page.getByRole("link", { name: title }).click();
  await expect(page).toHaveURL(new RegExp(`/notes/${slug}$`));
  await expect(page.getByTestId("public-note-markdown").getByRole("heading", { name: `Shared heading ${uniqueId}` })).toBeVisible();

  await page.goto("/app");
  await page.getByRole("link", { name: title }).click();
  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit/);
  await page.getByRole("button", { name: "Unpublish note" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?unpublished=1$/);
  await expect(page.getByText("Note unpublished.")).toBeVisible();

  await page.goto("/");
  await expect(page.getByRole("link", { name: title })).toHaveCount(0);

  const response = await page.goto(`/notes/${slug}`);
  expect(response?.status()).toBe(404);
  await expect(page.getByText("This page could not be found.")).toBeVisible();
});

