141	async function expectAccessibleStructure(page: Page) {
142	  const audit = await page.evaluate(() => {
143	    const issues: string[] = [];
144	
145	    const getLabelText = (element: Element) => {
146	      const ariaLabel = element.getAttribute("aria-label")?.trim();
147	      if (ariaLabel) {
148	        return ariaLabel;
149	      }
150	
151	      const labelledBy = element.getAttribute("aria-labelledby");
152	      if (labelledBy) {
153	        const text = labelledBy
154	          .split(/\s+/)
155	          .map((id) => document.getElementById(id)?.textContent?.trim() ?? "")
156	          .join(" ")
157	          .trim();
158	
159	        if (text) {
160	          return text;
161	        }
162	      }
163	
164	      if (
165	        element instanceof HTMLInputElement ||
166	        element instanceof HTMLTextAreaElement ||
167	        element instanceof HTMLSelectElement
168	      ) {
169	        const label = element.labels?.[0]?.textContent?.trim();
170	
171	        if (label) {
172	          return label;
173	        }
174	      }
175	
176	      return element.textContent?.trim() ?? "";
177	    };
178	
179	    const interactive = document.querySelectorAll("a[href], button, input:not([type='hidden']), textarea, select");
180	
181	    interactive.forEach((element) => {
182	      if (!getLabelText(element)) {
183	        const id = element.id ? `#${element.id}` : "";
184	        issues.push(`unnamed:${element.tagName.toLowerCase()}${id}`);
185	      }
186	    });
187	
188	    document.querySelectorAll("nav").forEach((element, index) => {
189	      if (!element.getAttribute("aria-label")) {
190	        issues.push(`unlabeled-nav:${index + 1}`);
191	      }
192	    });
193	
194	    return {
195	      h1Count: document.querySelectorAll("h1").length,
196	      issues,
197	      lang: document.documentElement.lang,
198	      mainCount: document.querySelectorAll("main").length
199	    };
200	  });
201	
202	  expect(audit.lang).toBe("en");
203	  expect(audit.mainCount).toBe(1);
204	  expect(audit.h1Count).toBeGreaterThan(0);
205	  expect(audit.issues).toEqual([]);
206	}
