208	async function expectShowroomRhythm(page: Page, viewport: "desktop" | "mobile") {
209	  const cards = page.locator(".public-note-showroom .note-preview-card");
210	  const boxes = await cards.evaluateAll((elements) =>
211	    elements.map((element) => {
212	      const rect = element.getBoundingClientRect();
213	
214	      return {
215	        height: Math.round(rect.height),
216	        width: Math.round(rect.width),
217	        x: Math.round(rect.x),
218	        y: Math.round(rect.y)
219	      };
220	    })
221	  );
222	  const variants = await cards.evaluateAll((elements) => elements.map((element) => element.getAttribute("data-card-variant")));
223	  const uniqueHeights = [...new Set(boxes.map((box) => box.height))];
224	
225	  expect(new Set(variants).size).toBeGreaterThanOrEqual(3);
226	  expect(uniqueHeights.length).toBeGreaterThanOrEqual(viewport === "desktop" ? 3 : 2);
227	  expect(Math.max(...boxes.map((box) => box.height)) - Math.min(...boxes.map((box) => box.height))).toBeGreaterThan(
228	    viewport === "desktop" ? 72 : 48
229	  );
230	
231	  if (viewport === "desktop") {
232	    expect(new Set(boxes.slice(0, 4).map((box) => box.x)).size).toBeGreaterThanOrEqual(2);
233	  } else {
234	    expect(Math.max(...boxes.map((box) => box.x)) - Math.min(...boxes.map((box) => box.x))).toBeLessThanOrEqual(2);
235	    expect(boxes[1]?.y).toBeGreaterThan(boxes[0]?.y ?? 0);
236	  }
237	}
